CREATE DATABASE IF NOT EXISTS usersdb;
CREATE DATABASE IF NOT EXISTS pharmacy_catalog_db;
CREATE DATABASE IF NOT EXISTS pharmacy_orders;
CREATE DATABASE IF NOT EXISTS pharmacy_admin_db;

USE usersdb;
SET @admin_id = (SELECT id FROM users WHERE username = 'admin' LIMIT 1);
SET @alice_id = (SELECT id FROM users WHERE username = 'alice' LIMIT 1);
SET @bob_id = (SELECT id FROM users WHERE username = 'bob' LIMIT 1);
UPDATE addresses SET is_default = b'0' WHERE user_id IN (@admin_id, @alice_id, @bob_id);
UPDATE addresses SET city = 'Bengaluru', state = 'Karnataka', is_default = b'1' WHERE user_id = @admin_id AND street_address = '1 Admin Block' AND pincode = 560048;
UPDATE addresses SET city = 'Bengaluru', state = 'Karnataka', is_default = b'1' WHERE user_id = @alice_id AND street_address = '221 MG Road' AND pincode = 560001;
